final:
module branch_predictor (  
    input [1:0] state,  
    input taken,  
    output reg [1:0] obf_next_state  
);  

always @(*) begin  
    case ({state, taken})  
        3'b000: obf_next_state = 2'b00;  
        3'b001: obf_next_state = 2'b01;  
        3'b010: obf_next_state = 2'b00;  
        3'b011: obf_next_state = 2'b10;  
        3'b100: obf_next_state = 2'b01;  
        3'b101: obf_next_state = 2'b11;  
        3'b110: obf_next_state = 2'b10;  
        3'b111: obf_next_state = 2'b11;  
        default: obf_next_state = state;  
    endcase  
end  
endmodule
